#[repr(transparent)]
#[transparent(u64_be)]
pub struct Fuid<H>(pub u64_be, PhantomData<H>);

unsafe impl<T> Zeroable for Fuid<T> {}
unsafe impl<T: 'static> Pod for Fuid<T> {}

impl<T> Clone for Fuid<T> {
    fn clone(&self) -> Self {
        *self
