                #[inline]
                fn try_convert_to_bytes(&self, slice: &mut [u8], cursor: &mut usize) -> rapira::Result<()> {
                    Ok(())
                }

                #[inline]
                fn convert_to_bytes(&self, slice: &mut [u8], cursor: &mut usize) {}

                #[inline]
                fn size(&self) -> usize { 0 }
