                        Some(with_attr) => {
                            from_slice_versioned.push(quote! {
                                let #ident: #typ = #with_attr::from_slice(slice)?;
                            });
                        }
                        None => {
                            from_slice_versioned.push(quote! {
                                let #ident = <#typ as rapira::Rapira>::from_slice_versioned(slice, version)?;
                            });
