                        min_size.push(quote! {
                            #with_attr::min_size(core::marker::PhantomData::<#typ>),
                        });
                        size.push(
                            quote! { + (match #with_attr::static_size(core::marker::PhantomData::<#typ>) {
                                Some(s) => s,
                                None => #with_attr::size(&self.#ident)
                            }) },
