                                #field_name.try_convert_to_bytes(slice, cursor)?;
                            });
                            fields_convert_to_bytes.push(quote! {
                                #field_name.convert_to_bytes(slice, cursor);
                            });
                        }
                    }
                }

                size.push(quote! {
                    #name::#variant_name(#(#field_names)*) => {
