                            });
                            fields_from_slice_unchecked.push(quote! {
                                let #field_name = <#typ as rapira::Rapira>::from_slice_unchecked(slice)?;
                            });
                            fields_from_slice_unsafe.push(quote! {
                                let #field_name = <#typ as rapira::Rapira>::from_slice_unsafe(slice)?;
