};

pub fn enum_serializer(
    data_enum: &DataEnum,
    name: &Ident,
    static_size: Option<Expr>,
    min_size: Option<Expr>,
    generics: Generics,
    is_debug: bool,
) -> proc_macro::TokenStream {
    let variants_len = data_enum.variants.len();

