                        Ok(#name::#variant_name)
                    }
                });
                convert_to_bytes_ctx.push(quote! {
                    #name::#variant_name => {
                        rapira::push(slice, cursor, #variant_id);
                    }
                });
                from_slice_ctx.push(quote! {
                    #variant_id => {
                        Ok(#name::#variant_name)
                    }
