                    },
                });
                enum_sizes.push(quote! {
                    rapira::static_size([#(#fields_static_sizes)*]),
                });
                min_sizes.push(quote! {
                    rapira::min_size(&[#(#fields_min_sizes)*]),
                });
                from_slice.push(quote! {
                    #variant_id => {
                        #(#fields_from_slice)*
                        Ok(#name::#variant_name{#(#field_names)*})
                    }
                });
                debug_from_slice.push(quote! {
                    #variant_id => {
                        println!("Variant: {}::{}", stringify!(#name), stringify!(#variant_name));
                        #(#fields_debug_from_slice)*
                        Ok(#name::#variant_name{#(#field_names)*})
                    }
                });
                check_bytes.push(quote! {
                    #variant_id => {
                        #(#fields_check_bytes)*
                    }
                });
                from_slice_unchecked.push(quote! {
                    #variant_id => {
                        #(#fields_from_slice_unchecked)*
                        Ok(#name::#variant_name{#(#field_names)*})
                    }
                });

                from_slice_unsafe.push(quote! {
                    #variant_id => {
                        #(#fields_from_slice_unsafe)*
                        Ok(#name::#variant_name{#(#field_names)*})
                    }
                });

                try_convert_to_bytes.push(quote! {
                    #name::#variant_name{#(#field_names)*} => {
                        rapira::push(slice, cursor, #variant_id);
                        #(#fields_try_convert_to_bytes)*
                    }
                });

                convert_to_bytes.push(quote! {
                    #name::#variant_name{#(#field_names)*} => {
                        rapira::push(slice, cursor, #variant_id);
                        #(#fields_convert_to_bytes)*
                    }
                });
            }
        }
    }

    let static_size = match static_size {
        Some(static_size) => {
            quote! {
                #static_size
            }
        }
        None => {
            quote! {
                rapira::enum_size([#(#enum_sizes)*])
            }
        }
    };
    let min_size = match min_size {
        Some(min_size) => {
            quote! {
                #min_size
            }
        }
        None => {
            quote! {
                rapira::enum_min_size(&[#(#min_sizes)*])
            }
        }
    };

    let name_with_generics = build_ident(name, generics);

    let debug_parse = if is_debug {
        quote! {
            /// Deserializes a value from a byte slice with debug logging.
            /// This method logs the enum variant name, field names, types, and values during deserialization.
            /// Useful for debugging serialization/deserialization issues.
            #[inline]
            fn debug_from_slice(slice: &mut &[u8]) -> rapira::Result<Self>
            where
                Self: Sized + std::fmt::Debug,
            {
                let val: u8 = rapira::byte_rapira::from_slice(slice)?;
                match val {
                    #(#debug_from_slice)*
                    _ => Err(rapira::RapiraError::EnumVariant),
                }
            }
        }
    } else {
        quote!()
    };

    let res = quote! {
        #name_with_generics {
            const STATIC_SIZE: Option<usize> = #static_size;
            const MIN_SIZE: usize = #min_size;

            #[inline]
            fn from_slice(slice: &mut &[u8]) -> rapira::Result<Self>
            where
                Self: Sized,
            {
                let val: u8 = rapira::byte_rapira::from_slice(slice)?;
                match val {
                    #(#from_slice)*
                    _ => Err(rapira::RapiraError::EnumVariant),
                }
            }

            #debug_parse

            #[inline]
            fn check_bytes(slice: &mut &[u8]) -> rapira::Result<()>
            where
                Self: Sized,
            {
                let val: u8 = rapira::byte_rapira::from_slice(slice)?;
                match val {
                    #(#check_bytes)*
                    _ => return Err(rapira::RapiraError::EnumVariant),
                }
                Ok(())
            }

            #[inline]
            unsafe fn from_slice_unchecked(slice: &mut &[u8]) -> rapira::Result<Self>
            where
                Self: Sized,
            {
                let val: u8 = rapira::byte_rapira::from_slice(slice)?;
                match val {
                    #(#from_slice_unchecked)*
                    _ => Err(rapira::RapiraError::EnumVariant),
                }
            }

            #[inline]
            unsafe fn from_slice_unsafe(slice: &mut &[u8]) -> rapira::Result<Self>
            where
                Self: Sized,
            {
                let val: u8 = rapira::byte_rapira::from_slice_unsafe(slice)?;
                match val {
                    #(#from_slice_unsafe)*
                    _ => Err(rapira::RapiraError::EnumVariant),
                }
            }

            #[inline]
            fn try_convert_to_bytes(&self, slice: &mut [u8], cursor: &mut usize) -> rapira::Result<()> {
                match self {
                    #(#try_convert_to_bytes)*
                }
                Ok(())
            }

            #[inline]
            fn convert_to_bytes(&self, slice: &mut [u8], cursor: &mut usize) {
                match self {
                    #(#convert_to_bytes)*
                }
            }

            #[inline]
            fn size(&self) -> usize {
                1 + match self {
                    #(#size)*
                }
            }
        }
    };

    proc_macro::TokenStream::from(res)
}

