                let mut fields_static_sizes: Vec<TokenStream> = Vec::with_capacity(len);
                let mut fields_min_sizes: Vec<TokenStream> = Vec::with_capacity(len);
                let mut fields_size: Vec<TokenStream> = Vec::with_capacity(len);
